mapper.update:
/*DisTrgFnlMapper.updateDisTrgMst*/ UPDATE MSP_DIS_TRG_MST SET PROC_YN = #{procYn}, PROC_ID = 'BATCH2', PROC_DTTM = SYSDATE WHERE 1=1 AND REGST_DT BETWEEN #{strDt} AND #{endDt}
AND PROC_YN= 'N'
AND PROC_YN= 'T'

mapper.select:
        /*DisTrgFnlMapper.checkEnggDt*/
        SELECT COUNT(CONTRACT_NUM) FROM 


	        	(SELECT 
	        		CONTRACT_NUM, 
				    TO_CHAR(ADD_MONTHS(TO_DATE(MAX(APP_START_DD), 'YYYYMMDDHH24MISS'), #{enggMnthCnt}) - 1, 'YYYYMMDD') ENGG_END_DT
				FROM MSP_JUO_ADD_INFO 
				WHERE 1 = 1
				    AND CONTRACT_NUM = #{contractNum}
				    AND EVNT_CD = #{evntCd}
				    AND EVNT_TRTM_DT = #{evntTrtmDt}
				GROUP BY CONTRACT_NUM)


        		VW_CNTR_ENGG_SELF


        WHERE 1 = 1
        	AND CONTRACT_NUM = #{contractNum}
          	AND ENGG_END_DT  >  #{baseDate}

/*DisTrgFnlMapper.compareDateWithApd*/
SELECT COUNT(CONTRACT_NUM)
FROM MSP_DIS_APD
WHERE CONTRACT_NUM = #{contractNum}
  AND REGST_DT  >=  #{effectiveDate}

mapper.update:
/*DisTrgFnlMapper.updateEachDisTrgFnlInfo*/
UPDATE MSP_DIS_TRG_FNL_INF
SET  PROC_YN= 'T'
    ,PROC_ID= 'BATCH2'
    ,PROC_DTTM= SYSDATE
    ,RSLT_CD= #{rsltCd}
    ,PRCS_SBST= #{prcsSbst}

    ,PRMT_ID= #{prmtId}


    ,OPEN_AGNT_CD= #{openAgntCd}


    ,PRMT_AGNT_CD= #{prmtAgntCd}


    ,ENGG_MNTH_CNT= #{enggMnthCnt}


    ,RATE_CD= #{rateCd}


    ,SLS_NO= #{slsNo}


    ,SLS_TP= #{slsTp}


    ,MODEL_ID= #{modelId}


    ,MODEL_NM= #{modelNm}

WHERE TRG_FNL_INF_SEQ = #{trgFnlInfSeq}

mapper.select:
/*DisTrgFnlMapper.findDisPrmtId*/
SELECT DISTINCT PRMT_ID
FROM VW_DIS_PRMT_DTL
WHERE USG_YN= 'Y'
  AND EVNT_CD= #{evntCd}
  AND ORGN_ID= #{prmtAgntCd}
  AND RATE_CD= #{rateCd}
  AND SLS_TP= #{slsTp}
  AND ENGG_SRL LIKE '%' || #{enggMnthCnt} || '%'
  AND (#{effectiveDate} BETWEEN STRT_DTTM AND END_DTTM)
  AND TO_CHAR(ORGN_REGST_DTTM,'YYYYMMDDHH24MISS')  <=  #{effectiveDate}


        AND (INTM_YN= 'Y' AND MODEL_ID= #{modelId})


        AND INTM_YN= 'N'

mapper.insert:
/*DisTrgFnlMapper.insertDisTrgFnl*/

    SELECT 'TF' || TO_CHAR(SYSDATE,'YYYYMMDD') || TRIM(TO_CHAR(SQ_DIS_TF.NEXTVAL, '000000')) AS trgFnlSeq FROM DUAL

INSERT INTO MSP_DIS_TRG_FNL
    (TRG_FNL_SEQ,TRG_FNL_INF_SEQ,REGST_DT,PROC_YN,CONTRACT_NUM,PRMT_ID,EVNT_CD,EVNT_TRTM_NO,EVNT_TRTM_DT,EFFECTIVE_DATE,REGST_ID,REGST_DTTM)
VALUES
    (
       #{trgFnlSeq}
      ,#{trgFnlInfSeq}
      ,TO_CHAR(SYSDATE, 'YYYYMMDD')
      ,'N'
      ,#{contractNum}
      ,#{prmtId}
      ,#{evntCd}
      ,#{evntTrtmNo}
      ,#{evntTrtmDt}
      ,#{effectiveDate}
      ,'BATCH2'
      ,SYSDATE
    )
